/// Function type information.
#[derive(Debug, Clone)]
pub struct FunctionInfo {
    pub name: String,
    pub params: Vec<(String, TypeInfo)>,
    pub return_type: Box<TypeInfo>,
    pub is_async: bool,
    pub is_method: bool,
}

impl FunctionInfo {
    /// Generate Rust function signature.
    #[must_use]
