#[derive(Debug, Clone)]
pub struct ImportInfo {
    pub path: String,
    pub names: Vec<String>,
    pub is_native: bool,
}

/// Analyze a source file.
pub fn analyze(source: &crate::parser::SourceFile) -> crate::Result<AnalysisResult> {
    let mut ctx = AnalysisContext::new(source);
    let mut type_inferrer = TypeInferrer::new();
    let mut ownership_analyzer = OwnershipAnalyzer::new();
    let mut validator = SubsetValidator::new();

    // Check for parse errors first
    if !source.errors.is_empty() {
        for err in &source.errors {
            ctx.add_warning(
                source.path.display().to_string(),
                format!("Parse error: {}", err),
                "parse_error",
            );
        }
    }

    // Validate the subset
    if let Err(e) = validator.validate(source) {
        ctx.add_warning(
            e.location,
            e.message,
            e.code,
        );
    }

    // Infer types from source
    let types = type_inferrer.infer_from_source(source)?;

    // Analyze ownership
    let ownership = ownership_analyzer.analyze(&types)?;

    // Build exports from types
    let exports = types
        .iter()
        .filter(|(_, info)| matches!(info, TypeInfo::Function(_)))
        .map(|(name, info)| {
            let rust_name = to_snake_case(name);
            ExportInfo {
                name: name.to_string(),
                rust_name,
                type_info: info.clone(),
            }
        })
        .collect();

    Ok(AnalysisResult {
        types,
        ownership,
        warnings: ctx.take_warnings(),
        exports,
        imports: Vec::new(),
    })
}

fn to_snake_case(s: &str) -> String {
    let mut result = String::new();
    for (i, c) in s.chars().enumerate() {
        if c.is_uppercase() && i > 0 {
            result.push('_');
        }
        result.push(c.to_ascii_lowercase());
    }
    result
}

//! # Ownership Analysis
//!
//! Infers Rust ownership patterns from TypeScript usage.

use super::{BorrowMode, TypeMap, OwnershipAnalysis, TypeInfo};

/// Borrow mode for a binding.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BorrowMode {
    /// Immutable borrow `&T`
    Shared,
    /// Mutable borrow `&mut T`
    Mut,
    /// Owned value `T`
    Owned,
    /// Unknown mode
    Unknown,
}

impl BorrowMode {
    /// Check if this mode allows mutation.
    #[must_use]
    pub fn is_mutable(&self) -> bool {
        matches!(self, BorrowMode::Mut | BorrowMode::Owned)
    }

    /// Combine two borrow modes.
    #[must_use]
    #[allow(clippy::similar_names)]
    pub fn combine(self, other: BorrowMode) -> BorrowMode {
        use BorrowMode::*;
        match (self, other) {
            (Unknown, m) | (m, Unknown) => m,
            (Shared, Shared) => Shared,
            (Mut, _) | (_, Mut) => Mut,
            (Owned, Owned) => Owned,
            (Shared, Owned) | (Owned, Shared) => Owned,
        }
    }

    /// Convert to Rust reference prefix.
    #[must_use]
    pub fn to_rust_prefix(&self) -> &'static str {
        match self {
            BorrowMode::Shared => "&",
            BorrowMode::Mut => "&mut ",
            BorrowMode::Owned => "",
            BorrowMode::Unknown => "&",
        }
    }
}

/// Analyzes ownership and borrowing patterns.
#[derive(Debug)]
pub struct OwnershipAnalyzer {
    /// Consumed values (moved)
    consumed: Vec<String>,
    /// Mutable references taken
    mut_refs: Vec<String>,
    /// Shared references taken
    shared_refs: Vec<String>,
}

impl OwnershipAnalyzer {
    /// Create a new ownership analyzer.
    #[must_use]
    pub fn new() -> Self {
        Self {
            consumed: Vec::new(),
            mut_refs: Vec::new(),
            shared_refs: Vec::new(),
        }
    }

    /// Analyze types and produce ownership information.
    #[must_use]
    pub fn analyze(&mut self, types: &TypeMap) -> OwnershipAnalysis {
        let mut ownership = OwnershipAnalysis::default();

        for (name, info) in types.iter() {
            let mode = self.infer_mode(name, info);
            ownership.set(name.to_string(), mode);
        }

        ownership
    }

    /// Infer borrow mode from type info and usage patterns.
    fn infer_mode(&self, _name: &str, info: &TypeInfo) -> BorrowMode {
        match info {
            // Functions that take &mut self are mutable
            TypeInfo::Function(f) if f.is_method => BorrowMode::Mut,
            // Strings are usually borrowed unless mutated
            TypeInfo::String | TypeInfo::StringLiteral(_) => BorrowMode::Shared,
            // Arrays can be borrowed or owned
            TypeInfo::Array(_) => BorrowMode::Owned,
            // Primitives are usually owned or small-copied
            TypeInfo::Integer(_) | TypeInfo::Float | TypeInfo::Boolean => BorrowMode::Owned,
            // Complex types are usually owned
            TypeInfo::Struct(_) | TypeInfo::Enum(_) => BorrowMode::Owned,
            // Options and Results are usually owned
            TypeInfo::Option(_) | TypeInfo::Result(_, _) => BorrowMode::Owned,
            // Unknown defaults to shared
            TypeInfo::Unknown => BorrowMode::Unknown,
            // Generics default to owned
            TypeInfo::Generic(_) => BorrowMode::Owned,
        }
    }

    /// Record that a value was consumed (moved).
    pub fn record_consume(&mut self, name: &str) {
        self.consumed.push(name.to_string());
    }

    /// Record that a mutable reference was taken.
    pub fn record_mut_ref(&mut self, name: &str) {
        self.mut_refs.push(name.to_string());
    }

    /// Record that a shared reference was taken.
    pub fn record_shared_ref(&mut self, name: &str) {
        self.shared_refs.push(name.to_string());
    }

    /// Check if a value was consumed (moved).
    #[must_use]
    pub fn was_consumed(&self, name: &str) -> bool {
        self.consumed.contains(&name.to_string())
    }
}

impl Default for OwnershipAnalyzer {
    fn default() -> Self {
        Self::new()
    }
}

//! # Analysis Context
//!
//! Maintains state during analysis.

use crate::parser::SourceFile;
use super::{TypeInfo, AnalysisWarning};

/// Context for type and ownership analysis.
#[derive(Debug)]
pub struct AnalysisContext {
    /// Source file being analyzed
    source: SourceFile,
    /// Current line being processed
    current_line: u32,
    /// Current column being processed
    current_column: u32,
    /// Accumulated warnings
    warnings: Vec<AnalysisWarning>,
    /// Scope stack for variable resolution
    scopes: Vec<std::collections::HashMap<String, TypeInfo>>,
}

impl AnalysisContext {
    /// Create a new analysis context.
    #[must_use]
    pub fn new(source: &SourceFile) -> Self {
        Self {
            source: source.clone(),
            current_line: 1,
            current_column: 1,
            warnings: Vec::new(),
            scopes: vec![std::collections::HashMap::new()],
        }
    }

    /// Get the current source location as a string.
    #[must_use]
    pub fn current_location(&self) -> String {
        format!("{}:{}:{}", self.source.path.display(), self.current_line, self.current_column)
    }

    /// Update current location from line and column.
    pub fn set_location(&mut self, line: u32, column: u32) {
        self.current_line = line;
        self.current_column = column;
    }

    /// Add a warning.
    pub fn add_warning(&mut self, location: String, message: String, code: &'static str) {
        self.warnings.push(AnalysisWarning {
            location,
            message,
            code,
        });
    }

    /// Add a warning at current location.
    pub fn warn(&mut self, message: String, code: &'static str) {
        self.add_warning(self.current_location(), message, code);
    }

    /// Take all warnings.
    #[must_use]
    pub fn take_warnings(&mut self) -> Vec<AnalysisWarning> {
        std::mem::take(&mut self.warnings)
    }

    /// Push a new scope.
    pub fn push_scope(&mut self) {
        self.scopes.push(std::collections::HashMap::new());
    }

    /// Pop the current scope.
    pub fn pop_scope(&mut self) {
        if self.scopes.len() > 1 {
            self.scopes.pop();
        }
    }

    /// Declare a variable in the current scope.
    pub fn declare(&mut self, name: String, info: TypeInfo) {
        if let Some(scope) = self.scopes.last_mut() {
            scope.insert(name, info);
        }
    }

    /// Resolve a variable name in scopes.
    #[must_use]
    pub fn resolve(&self, name: &str) -> Option<&TypeInfo> {
        for scope in self.scopes.iter().rev() {
            if let Some(info) = scope.get(name) {
                return Some(info);
            }
        }
        None
    }

    /// Check if a string is a reserved Rust keyword.
    #[must_use]
    pub fn is_rust_keyword(&self, s: &str) -> bool {
        Self::RUST_KEYWORDS.contains(s)
    }

    /// Mangle a name to avoid Rust keyword conflicts.
    #[must_use]
    pub fn mangle_name(&self, name: &str) -> String {
        if self.is_rust_keyword(name) {
            format!("{}_rune", name)
        } {
            name.to_string()
        }
    }

    /// Get source file path.
    #[must_use]
    pub fn source_path(&self) -> &std::path::Path {
        &self.source.path
    }

    /// Get the raw source text.
    #[must_use]
    pub fn source_text(&self) -> &str {
        &self.source.source
    }

    /// Check if this is a TSX file.
    #[must_use]
    pub fn is_tsx(&self) -> bool {
        self.source.is_tsx()
    }

    /// Rust keywords that need mangling.
    const RUST_KEYWORDS: phf::Set<&'static str> = phf::phf_set! {
        "as", "async", "await", "break", "const", "continue", "crate", "dyn",
        "else", "enum", "extern", "false", "fn", "for", "if", "impl", "in",
        "let", "loop", "match", "mod", "move", "mut", "pub", "ref", "return",
        "self", "Self", "static", "struct", "super", "trait", "true", "type",
        "unsafe", "use", "where", "while", "abstract", "become", "box", "do",
        "final", "fn", "macro", "override", "priv", "try", "typeof", "unsized",
        "virtual", "yield",
    };
}

//! # Type Inference Module
//!
//! Infers Rust types from TypeScript source.

mod primitives;
mod ts_types;

use crate::parser::SourceFile;
use crate::analyzer::{TypeMap, TypeInfo, FunctionInfo, StructInfo, EnumInfo, EnumVariant};

/// Main type inference engine.
#[derive(Debug)]
pub struct TypeInferrer {
    /// Inferred types for this file
    types: TypeMap,
    /// Module name
    module_name: String,
}

impl TypeInferrer {
    /// Create a new type inferrer.
    #[must_use]
    pub fn new() -> Self {
        Self {
            types: TypeMap::default(),
            module_name: String::new(),
        }
    }

    /// Infer all types from source text.
    #[must_use]
    pub fn infer_from_source(&mut self, source: &SourceFile) -> crate::Result<TypeMap> {
        self.module_name = source.module_name().to_string();
        let mut types = TypeMap::default();

        // Parse types from source text using regex-like patterns
        self.infer_types_from_text(&source.source, &mut types);

        self.types = types.clone();
        Ok(types)
    }

    /// Infer types from source text using simple pattern matching.
    fn infer_types_from_text(&self, source: &str, types: &mut TypeMap) {
        // Find function declarations: function name(args): returnType
        for line in source.lines() {
            let line = line.trim();

            // Skip comments
            if line.starts_with("//") || line.starts_with("/*") {
                continue;
            }

            // Function declarations
            if let Some(func) = self.parse_function(line) {
                types.insert(func.name.clone(), TypeInfo::Function(func));
            }

            // Type aliases: export type Name = { ... }
            if let Some(struct_info) = self.parse_type_alias(line, source) {
                types.insert(struct_info.name.clone(), TypeInfo::Struct(struct_info));
            }

            // Enum declarations
            if let Some(enum_info) = self.parse_enum(line) {
                types.insert(enum_info.name.clone(), TypeInfo::Enum(enum_info));
            }
        }

        // Parse interface definitions (multi-line)
        self.parse_interfaces(source, types);
    }

    /// Parse a function declaration from a line.
    fn parse_function(&self, line: &str) -> Option<FunctionInfo> {
        // Pattern: export function name(args): returnType
        // or: function name(args): returnType
        let pattern = if line.starts_with("export") {
            "export function "
        } else {
            "function "
        };

        let rest = line.strip_prefix(pattern)?;
        let rest = rest.strip_prefix("async ")?/span>)?</span>;
        let rest = rest.strip_prefix("pub ")?/span>)?;

        // Extract function name
        let (name, rest) = self.extract_identifier(rest)?;

        // Extract parameters
        let (params_str, rest) = self.extract_in_parens(rest)?;

        // Extract return type
        let return_type = if let Some(ret) = rest.strip_prefix("): ") {
            self.parse_type(ret.trim_end_matches(';'))
        } else {
            Box::new(TypeInfo::Unknown)
        };

        let params = self.parse_params(params_str);

        Some(FunctionInfo {
            name,
            params,
            return_type,
            is_async: line.contains("async function"),
            is_method: false,
        })
    }

    /// Extract an identifier from the start of a string.
    fn extract_identifier(&self, s: &str) -> Option<(String, &str)> {
        let mut chars = s.chars().peekable();
        let mut result = String::new();

        // Handle generics: name<T>
        let mut in_generic = false;

        while let Some(c) = chars.next() {
            match c {
                '<' => {
                    in_generic = true;
                    result.push(c);
                }
                '>' if in_generic => {
                    in_generic = false;
                    result.push(c);
                }
                'a'..='z' | 'A'..='Z' | '_' | '0'..='9' if in_generic || !result.is_empty() => {
                    result.push(c);
                }
                _ if !result.is_empty() => {
                    return Some((result, &s[s.len() - chars.count() - 1..]));
                }
                _ => {
                    if !result.is_empty() {
                        return Some((result, &s[s.len() - chars.count()..]));
                    }
                }
            }
        }

        if !result.is_empty() {
            Some((result, ""))
        } else {
            None
        }
    }

    /// Extract content within parentheses.
    fn extract_in_parens(&self, s: &str) -> Option<(String, &str)> {
        let mut depth = 0;
        let mut start = None;

        for (i, c) in s.chars().enumerate() {
            match c {
                '(' if depth == 0 => start = Some(i + 1),
                '(' => depth += 1,
                ')' if depth == 0 => {
                    let end = i;
                    let content = &s[start?..end];
                    let rest = s[i + 1..].trim_start();
                    return Some((content.to_string(), rest));
                }
                ')' => depth -= 1,
                _ => {}
            }
        }
        None
    }

    /// Parse parameter list.
    fn parse_params(&self, params_str: &str) -> Vec<(String, TypeInfo)> {
        let mut params = Vec::new();

        for param in params_str.split(',') {
            let param = param.trim();
            if param.is_empty() {
                continue;
            }

            // Pattern: name: type
            if let Some((idx, _)) = param.match_indices(": ") {
                let name = param[..idx].trim().to_string();
                let type_str = param[idx + 2..].trim();
                let type_info = self.parse_type(type_str);
                params.push((name, type_info));
            } else if let Some((idx, _)) = param.match_indices(':') {
                let name = param[..idx].trim().to_string();
                let type_str = param[idx + 1..].trim();
                let type_info = self.parse_type(type_str);
                params.push((name, type_info));
            } else {
                // Infer from name or default
                params.push((param.to_string(), TypeInfo::Unknown));
            }
        }

        params
    }

    /// Parse a type string.
    fn parse_type(&self, type_str: &str) -> Box<TypeInfo> {
        let s = type_str.trim();

        // Remove trailing punctuation
        let s = s.trim_end_matches(|c: char| c == ';' || c == ',' || c == ')' || c == '>');

        // Void
        if s == "void" || s == "undefined" {
            return Box::new(TypeInfo::Unknown);
        }

        // Primitive types
        match s {
            "number" => return Box::new(TypeInfo::Float),
            "string" => return Box::new(TypeInfo::String),
            "boolean" => return Box::new(TypeInfo::Boolean),
            "null" => return Box::new(TypeInfo::Unknown),
            _ => {}
        }

        // String literals
        if (s.starts_with('"') && s.ends_with('"'))
            || (s.starts_with('\'') && s.ends_with('\'')) {
            return Box::new(TypeInfo::StringLiteral(s[1..s.len() - 1].to_string()));
        }

        // Integer literals
        if let Ok(n) = s.parse::<i64>() {
            return Box::new(TypeInfo::Integer(n));
        }

        // Array type: T[]
        if let Some(inner) = s.strip_suffix("[]") {
            return Box::new(TypeInfo::Array(self.parse_type(inner)));
        }

        // Option type: T | null
        if let Some(inner) = s.strip_suffix(" | null") {
            return Box::new(TypeInfo::Option(self.parse_type(inner)));
        }

        // Result type patterns
        if s.contains("ok:") && s.contains("error:") {
            return Box::new(TypeInfo::Result(
                Box::new(TypeInfo::Unknown),
                Box::new(TypeInfo::String),
            ));
        }

        // Generic type: Name<T>
        if let Some((name, generic)) = s.split_once('<') {
            let generic = generic.trim_end_matches('>');
            if generic.contains(',') {
                // Multiple type params - just use first
                let first = generic.split(',').next().unwrap_or("T");
                return Box::new(TypeInfo::Generic(format!("{}<{}>", name, first)));
            }
            return Box::new(TypeInfo::Generic(format!("{}<{}>", name, generic)));
        }

        // Regular type name
        Box::new(TypeInfo::Struct(StructInfo {
            name: s.to_string(),
            fields: Vec::new(),
        }))
    }

    /// Parse a type alias or interface.
    fn parse_type_alias(&self, line: &str, _source: &str) -> Option<StructInfo> {
        // Pattern: export type Name = { ... }
        let prefix = if line.starts_with("export") {
            line.strip_prefix("export ")?
        } else {
            line
        };

        let prefix = prefix.strip_prefix("type ")?;
        let (name, rest) = self.extract_identifier(prefix)?;

        if !rest.trim().starts_with('=') {
            return None;
        }

        let rest = rest.trim_start_matches('=').trim();

        // This is an alias to another type
        if !rest.starts_with('{') {
            return Some(StructInfo {
                name,
                fields: Vec::new(),
            });
        }

        None
    }

    /// Parse interface definitions (multi-line).
    fn parse_interfaces(&self, source: &str, types: &mut TypeMap) {
        let mut in_interface = false;
        let mut current_name = String::new();
        let mut brace_depth = 0;
        let mut fields = Vec::new();
        let mut current_field = String::new();

        for line in source.lines() {
            let line = line.trim();

            // Start of interface
            if line.starts_with("export type ")
                && (line.contains("= {") || line.contains(" ={")) {
                in_interface = true;
                let name_part = line.strip_prefix("export type ").unwrap();
                if let Some((name, _)) = self.extract_identifier(name_part) {
                    current_name = name;
                }
                brace_depth = line.matches('{').count() - line.matches('}').count();

                // Extract fields from same line if present
                if let Some(start) = line.find('{') {
                    let end = line.rfind('}');
                    if let Some(end) = end {
                        let body = &line[start + 1..end];
                        for field in body.split(';') {
                            if let Some(f) = self.parse_field(field) {
                                fields.push(f);
                            }
                        }
                    }
                }
                continue;
            }

            if in_interface {
                brace_depth += line.matches('{').count() as i32;
                brace_depth -= line.matches('}').count() as i32;

                if brace_depth <= 0 {
                    // End of interface
                    types.insert(
                        current_name.clone(),
                        TypeInfo::Struct(StructInfo {
                            name: current_name.clone(),
                            fields: fields.clone(),
                        }),
                    );
                    in_interface = false;
                    fields.clear();
                    current_name.clear();
                } else if let Some(field) = self.parse_field(line) {
                    fields.push(field);
                }
            }
        }
    }

    /// Parse a single field from a line.
    fn parse_field(&self, line: &str) -> Option<(String, TypeInfo)> {
        let line = line.trim().trim_end_matches(',').trim_end_matches(';');

        if line.is_empty() || line.starts_with("//") {
            return None;
        }

        // Pattern: name: type
        if let Some((idx, _)) = line.match_indices(": ").next() {
            let name = line[..idx].trim().to_string();
            let type_str = line[idx + 2..].trim();
            let type_info = self.parse_type(type_str);
            return Some((name, *type_info));
        }

        // Pattern: name:type (no space)
        if let Some((idx, _)) = line.match_indices(':').next() {
            let name = line[..idx].trim().to_string();
            let type_str = line[idx + 1..].trim();
            let type_info = self.parse_type(type_str);
            return Some((name, *type_info));
        }

        None
    }

    /// Parse an enum declaration.
    fn parse_enum(&self, line: &str) -> Option<EnumInfo> {
        // Pattern: export enum Name
        let prefix = if line.starts_with("export ") {
            line.strip_prefix("export ")?
        } else {
            line
        };

        if !prefix.starts_with("enum ") {
            return None;
        }

        let rest = prefix.strip_prefix("enum ")?;
        let (name, _) = self.extract_identifier(rest)?;

        Some(EnumInfo {
            name,
            variants: Vec::new(),
        })
    }
}

impl Default for TypeInferrer {
    fn default() -> Self {
        Self::new()
    }
}

