/// Generated Rust module.
#[derive(Debug, Clone)]
pub struct GeneratedModule {
    /// Module name (file stem)
    pub name: String,
    /// Generated Rust source code
    pub source: String,
    /// Imports required by this module
    pub imports: Vec<Import>,
    /// Type definitions
    pub types: Vec<String>,
    /// Function definitions
    pub functions: Vec<String>,
}

/// An import statement.
#[derive(Debug, Clone)]
pub struct Import {
    /// Import path
    pub path: String,
    /// Imported names
    pub names: Vec<ImportedName>,
    /// Is this a native import?
    pub is_native: bool,
}

impl Import {
    /// Convert to Rust import statement.
    #[must_use]
    pub fn to_rust(&self) -> String {
        if self.is_native {
            format!("use crate::native::{};", self.path.replace(':', "::"))
        } else {
            let names: Vec<_> = self.names.iter()
                .map(|n| n.rust_name.clone())
                .collect();
            format!("use {}::{{{}}};", self.path.replace(".r.ts", "").replace(".r.tsx", ""), names.join(", "))
        }
    }
}

