//! # Expression Emitter
//!
//! Emits Rust code from TypeScript expressions.

use crate::analyzer::AnalysisResult;

/// Emits Rust code for expressions.
pub struct ExprEmitter<'a> {
    /// Output buffer
    output: String,
    /// Current indentation
    indent: usize,
    /// Analysis result
    _analysis: &'a AnalysisResult,
}

impl<'a> ExprEmitter<'a> {
    /// Create a new expression emitter.
    pub fn new(analysis: &'a AnalysisResult) -> Self {
        Self {
            output: String::new(),
            indent: 0,
            _analysis: analysis,
        }
    }

    /// Emit an expression.
    #[allow(unused)]
    pub fn emit_expr(&mut self, expr: &str) -> String {
        self.emit_string(expr);
        self.output.clone()
    }

    /// Emit an expression string to output.
    fn emit_string(&mut self, expr: &str) {
        self.output.push_str(expr);
    }

    /// Get the output.
    #[must_use]
    pub fn into_output(self) -> String {
        self.output
    }
}

//! # Statement Emitter
//!
//! Emits Rust code from TypeScript statements.

use crate::analyzer::AnalysisResult;
use super::expr::ExprEmitter;

/// Emits Rust code for statements.
pub struct StmtEmitter<'a> {
    /// Output buffer
    output: String,
    /// Current indentation
    indent: usize,
    /// Expression emitter reference
    expr_emitter: ExprEmitter<'a>,
}

impl<'a> StmtEmitter<'a> {
    /// Create a new statement emitter.
    pub fn new(analysis: &'a AnalysisResult) -> Self {
        Self {
            output: String::new(),
            indent: 0,
            expr_emitter: ExprEmitter::new(analysis),
        }
    }

    /// Emit a statement.
    #[allow(unused)]
    pub fn emit_stmt(&mut self, stmt: &str) {
        self.push_indent();
        self.push(stmt);
        self.push_line(";");
    }

    /// Get the output.
    #[must_use]
    pub fn into_output(self) -> String {
        self.output
    }

    fn push(&mut self, s: &str) {
        self.output.push_str(s);
    }

    fn push_line(&mut self, s: &str) {
        self.output.push_str(s);
        self.output.push('\n');
    }

    fn push_indent(&mut self) {
        for _ in 0..self.indent {
            self.output.push_str("    ");
        }
    }
}

//! # Type Emitter
//!
//! Emits Rust type declarations from TypeScript types.

use crate::analyzer::{TypeInfo, StructInfo, EnumInfo, FunctionInfo};

/// Emits Rust type code.
#[derive(Debug, Default)]
pub struct TypeEmitter;

impl TypeEmitter {
    /// Create a new type emitter.
    #[must_use]
    pub fn new() -> Self {
        Self
    }

    /// Emit a type declaration.
    #[must_use]
    pub fn emit_type(&self, type_info: &TypeInfo) -> String {
        type_info.to_rust_type()
    }
}

impl StructInfo {
    /// Generate Rust struct definition.
    #[must_use]
    pub fn to_rust(&self) -> String {
        let fields = self
            .fields
            .iter()
            .map(|(name, ty)| format!("    pub {}: {},", Self::to_snake_case(name), ty.to_rust_type()))
            .collect::<Vec<_>>()
            .join("\n");

        format!(
            "#[derive(Clone, Debug)]\npub struct {} {{\n{}\n}}",
            Self::to_pascal_case(&self.name),
            fields
        )
    }

    fn to_snake_case(s: &str) -> String {
        let mut result = String::new();
        for (i, c) in s.chars().enumerate() {
            if c.is_uppercase() && i > 0 {
                result.push('_');
            }
            result.push(c.to_ascii_lowercase());
        }
        result
    }

    fn to_pascal_case(s: &str) -> String {
        let mut result = String::new();
        let mut capitalize_next = true;
        for c in s.chars() {
            if c == '_' || c == '-' {
                capitalize_next = true;
            } else if capitalize_next {
                result.push(c.to_ascii_uppercase());
                capitalize_next = false;
            } else {
                result.push(c);
            }
        }
        result
    }
}

impl EnumInfo {
    /// Generate Rust enum definition.
    #[must_use]
    pub fn to_rust(&self) -> String {
        let variants = self
            .variants
            .iter()
            .map(|v| {
                if v.fields.is_empty() {
                    format!("    {},", Self::to_pascal_case(&v.tag))
                } else {
                    let fields = v
                        .fields
                        .iter()
                        .map(|(n, t)| format!("{}: {}", Self::to_snake_case(n), t.to_rust_type()))
                        .collect::<Vec<_>>()
                        .join(", ");
                    format!("    {} {{ {} }},", Self::to_pascal_case(&v.tag), fields)
                }
            })
            .collect::<Vec<_>>()
            .join("\n");

        format!(
            "#[derive(Clone, Debug)]\npub enum {} {{\n{}\n}}",
            Self::to_pascal_case(&self.name),
            variants
        )
    }

    fn to_snake_case(s: &str) -> String {
        let mut result = String::new();
        for (i, c) in s.chars().enumerate() {
            if c.is_uppercase() && i > 0 {
                result.push('_');
            }
            result.push(c.to_ascii_lowercase());
        }
        result
    }

    fn to_pascal_case(s: &str) -> String {
        let mut result = String::new();
        let mut capitalize_next = true;
        for c in s.chars() {
            if c == '_' || c == '-' {
                capitalize_next = true;
            } else if capitalize_next {
                result.push(c.to_ascii_uppercase());
                capitalize_next = false;
            } else {
                result.push(c);
            }
        }
        result
    }
}

impl FunctionInfo {
    /// Generate Rust function signature.
    #[must_use]
    pub fn to_rust_signature(&self) -> String {
        let params = self
            .params
            .iter()
            .map(|(n, t)| format!("{}: {}", Self::to_snake_case(n), t.to_rust_type()))
            .collect::<Vec<_>>()
            .join(", ");

        let async_prefix = if self.is_async { "async " } else { "" };

        format!(
            "{}fn({}) -> {}",
            async_prefix,
            params,
            self.return_type.to_rust_type()
        )
    }

    fn to_snake_case(s: &str) -> String {
        let mut result = String::new();
        for (i, c) in s.chars().enumerate() {
            if c.is_uppercase() && i > 0 {
                result.push('_');
            }
            result.push(c.to_ascii_lowercase());
        }
        result
    }
}

//! # JSX Transpiler
//!
//! Transpiles JSX/TSX syntax to Rust builder patterns (e.g., Ratatui).

/// Transpiles JSX to Rust builder patterns.
#[derive(Debug, Default)]
pub struct JsxTranspiler {
    /// Widget library to target
    library: WidgetLibrary,
}

/// Target widget library.
#[derive(Debug, Clone, Copy)]
pub enum WidgetLibrary {
    /// Ratatui (TUI)
    Ratatui,
    /// Iced (GUI)
    Iced,
    /// Custom
    Custom,
}

impl Default for JsxTranspiler {
    fn default() -> Self {
        Self::new(WidgetLibrary::Ratatui)
    }
}

impl JsxTranspiler {
    /// Create a new JSX transpiler.
    #[must_use]
    pub fn new(library: WidgetLibrary) -> Self {
        Self { library }
    }

    /// Transpile a JSX element.
    #[allow(unused)]
    pub fn transpile_element(&self, elem: &str) -> String {
        match self.library {
            WidgetLibrary::Ratatui => self.transpile_ratatui(elem),
            WidgetLibrary::Iced => self.transpile_iced(elem),
            WidgetLibrary::Custom => elem.to_string(),
        }
    }

    /// Transpile to Ratatui widgets.
    fn transpile_ratatui(&self, elem: &str) -> String {
        // Basic JSX to Ratatui translation
        let elem = elem.trim();

        // Parse tag name
        let (tag, rest) = if let Some(space) = elem.find(' ') {
            (&elem[..space], &elem[space..])
        } else if let Some(gt) = elem.find('>') {
            (&elem[..gt], &elem[gt..])
        } else {
            (elem.trim_end_matches('/'), "")
        };

        let tag = tag.trim_start_matches('<').trim_end_matches('/');

        // Translate common tags to Ratatui widgets
        let widget = match tag {
            "Block" => "Block::default()",
            "List" => "List::new(items)",
            "ListItem" => "ListItem::new(text)",
            "Paragraph" => "Paragraph::new(text)",
            "Text" => "Paragraph::new(text)",
            "Button" => "Button::default()",
            "Input" => "Paragraph::new(\"[input]\")",
            "VStack" => "Column::new()",
            "HStack" => "Row::new()",
            "Spacer" => "Constraint::new(0).expand()",
            _ => &format!("{tag}::default()"),
        };

        format!("{}.block()", widget)
    }

    /// Transpile to Iced widgets.
    fn transpile_iced(&self, elem: &str) -> String {
        let elem = elem.trim();
        let tag = elem.split_whitespace().next().unwrap_or("Text").trim_start_matches('<');

        match tag {
            "Text" => "text(\"\")".to_string(),
            "Button" => "Button::new(\"Click me\")".to_string(),
            "Column" => "Column::new()".to_string(),
            "Row" => "Row::new()".to_string(),
            _ => format!("{tag}::new()", tag = tag),
        }
    }

    /// Transpile JSX expression with props.
    #[allow(unused)]
    pub fn transpile_with_props(&self, elem: &str, props: &[(&str, &str)]) -> String {
        let mut result = self.transpile_element(elem);

        for (key, value) in props {
            result.push_str(&format!(".{}({})", key, value));
        }

        result
    }
}

//! # Driver Module
//!
//! Orchestrates the full compilation pipeline and integrates with Cargo.

mod build;
mod config;
mod cache;

pub use build::{BuildDriver, BuildOptions, BuildMode};
pub use config::RuneConfig;
pub use cache::CacheManager;

/// CLI commands supported by rune.
#[derive(Debug, Clone, Copy)]
pub enum Command {
    /// Development mode with hot reload
    Dev,
    /// Release build
    Build,
    /// Type check only
    Check,
    /// Transpile to stdout
    Transpile,
    /// Initialize new project
    Init,
}

impl Command {
    /// Parse from string.
    #[must_use]
    pub fn parse(s: &str) -> Option<Self> {
        match s {
            "dev" => Some(Self::Dev),
            "build" => Some(Self::Build),
            "check" => Some(Self::Check),
            "transpile" => Some(Self::Transpile),
            "init" => Some(Self::Init),
            _ => None,
        }
    }
}

/// Run the compiler with given options.
pub fn run(command: Command, options: BuildOptions) -> crate::Result<()> {
    let mut driver = BuildDriver::new(options)?;
    match command {
        Command::Dev => driver.dev(),
        Command::Build => driver.build(),
        Command::Check => driver.check(),
        Command::Transpile => driver.transpile(),
        Command::Init => driver.init(),
    }
}

//! # Build Driver
//!
//! Main compilation orchestration.

use std::path::PathBuf;
use std::process::Command as ProcCommand;
use crate::{Result, parser, analyzer, codegen};
use super::config::RuneConfig;
use super::cache::CacheManager;

/// Build mode.
#[derive(Debug, Clone, Copy)]
pub enum BuildMode {
    /// Development with hot reload
    Dev,
    /// Release build
    Release,
}

/// Options for building.
#[derive(Debug, Clone)]
pub struct BuildOptions {
    /// Mode to build in
    pub mode: BuildMode,
    /// Working directory
    pub workspace: PathBuf,
    /// Target crate name
    pub target_crate: Option<String>,
    /// Config file path
    pub config: Option<PathBuf>,
    /// File to transpile (for transpile command)
    pub transpile_file: Option<PathBuf>,
    /// Verbose output
    pub verbose: bool,
}

impl BuildOptions {
    /// Create new options.
    #[must_use]
    pub fn new(workspace: PathBuf) -> Self {
        Self {
            mode: BuildMode::Dev,
            workspace,
            target_crate: None,
            config: None,
            transpile_file: None,
            verbose: false,
        }
    }

    /// Set development mode.
    #[must_use]
    pub fn dev(mut self) -> Self {
        self.mode = BuildMode::Dev;
        self
    }

    /// Set release mode.
    #[must_use]
    pub fn release(mut self) -> Self {
        self.mode = BuildMode::Release;
        self
    }
}

/// Main build driver.
pub struct BuildDriver {
    options: BuildOptions,
    config: RuneConfig,
    cache: CacheManager,
}

impl BuildDriver {
    /// Create a new build driver.
    pub fn new(options: BuildOptions) -> Result<Self> {
        let config_path = options.config.clone()
            .or_else(|| Some(options.workspace.join("rune.toml")));

        let config = if let Some(ref path) = config_path {
            if path.exists() {
                RuneConfig::load(path)?
            } else {
                RuneConfig::default()
            }
        } else {
            RuneConfig::default()
        };

        let cache = CacheManager::new(&options.workspace)?;

        Ok(Self {
            options,
            config,
            cache,
        })
    }

    /// Run in development mode with hot reload.
    pub fn dev(&mut self) -> Result<()> {
        if self.options.verbose {
            println!("Running in development mode with hot reload...");
        }

        let sources = self.find_sources()?;
        if self.options.verbose {
            println!("Found {} Rune source files", sources.len());
        }

        let parsed = self.parse_sources(&sources)?;
        let analyses = self.analyze_sources(&parsed)?;
        let generated = self.generate_code(&parsed, &analyses)?;
        self.write_generated(&generated)?;
        self.build_crate(false)?;
        self.setup_hot_reload()?;

        if self.options.verbose {
            println!("Development build complete. Dylib ready.");
        }

        Ok(())
    }

    /// Run in release mode.
    pub fn build(&mut self) -> Result<()> {
        if self.options.verbose {
            println!("Running in release mode...");
        }

        let sources = self.find_sources()?;
        let parsed = self.parse_sources(&sources)?;
        let analyses = self.analyze_sources(&parsed)?;
        let generated = self.generate_code(&parsed, &analyses)?;
        self.write_generated(&generated)?;
        self.build_crate(true)?;

        if self.options.verbose {
            println!("Release build complete.");
        }

        Ok(())
    }

    /// Type check only.
    pub fn check(&mut self) -> Result<()> {
        let sources = self.find_sources()?;
        let parsed = self.parse_sources(&sources)?;
        let analyses = self.analyze_sources(&parsed)?;

        for analysis in &analyses {
            for warning in &analysis.warnings {
                println!("warning: {} at {}", warning.message, warning.location);
            }
        }

        println!("Type check passed for {} files.", parsed.len());
        Ok(())
    }

    /// Transpile a single file to stdout.
    pub fn transpile(&mut self) -> Result<()> {
        let file = self.options.transpile_file.as_ref()
            .ok_or_else(|| crate::RuneError::Codegen("No file specified".into()))?;

        let source = parser::parse_file(file)?;
        let analysis = analyzer::analyze(&source)?;
        let module = codegen::generate(&source, &analysis)?;

        println!("{}", module.source);
        Ok(())
    }

    /// Initialize a new project.
    #[allow(clippy::too_many_lines)]
    pub fn init(&mut self) -> Result<()> {
        let project_name = self.config.project.name.clone();
        let target_crate = self.config.build.target_crate.clone();

        let base = self.options.workspace.join("crates").join(&target_crate);
        std::fs::create_dir_all(base.join("src/native"))?;
        std::fs::create_dir_all(base.join("src/views"))?;

        let cargo = format!(r#"[package]
name = "{}"
version = "0.1.0"
edition = "2021"

[lib]
name = "{}"
path = "src/lib.rs"

[dependencies]
protocol = {{ path = "../protocol" }}
ratatui = "0.26"

[build-dependencies]
rune = {{ path = "../../.." }}
"#, target_crate, target_crate);

        std::fs::write(base.join("Cargo.toml"), cargo)?;

        let lib = r#"mod native;

pub struct AppState {
    pub tasks: Vec<Task>,
}

#[derive(Clone)]
pub struct Task {
    pub id: i32,
    pub title: String,
    pub done: bool,
}

#[no_mangle]
pub extern "C" fn create_app() -> *mut dyn protocol::App {
    Box::into_raw(Box::new(AppImpl))
}

struct AppImpl;

impl protocol::App for AppImpl {
    fn update(&mut self, _state: &mut AppState) {}
    fn render(&self, _term: &mut impl ratatui::backend::Backend, _state: &AppState) {}
}
"#;

        std::fs::write(base.join("src/lib.rs"), lib)?;

        let main_ts = "export function update(state: AppState): void {}\n\
export function render(state: AppState): void {}\n";

        std::fs::write(base.join("src/main.r.ts"), main_ts)?;

        let state_ts = "export type Task = { id: number; title: string; done: boolean };\n\
export type AppState = { tasks: Task[]; selected: number };\n";

        std::fs::write(base.join("src/state.r.ts"), state_ts)?;

        let native_mod = "pub mod fast_math;\n";
        std::fs::write(base.join("src/native/mod.rs"), native_mod)?;

        let fast_math = "pub fn fast_sqrt(x: f64) -> f64 { x.sqrt() }\n";
        std::fs::write(base.join("src/native/fast_math.rs"), fast_math)?;

        println!("Initialized Rune project: {}", project_name);
        println!("Created structure in crates/{}/", target_crate);

        Ok(())
    }

    fn find_sources(&self) -> Result<Vec<PathBuf>> {
        let src_dir = self.options.workspace
            .join("crates")
            .join(&self.config.build.target_crate)
            .join("src");

        parser::scan_directory(&src_dir)
    }

    fn parse_sources(&self, sources: &[PathBuf]) -> Result<Vec<parser::SourceFile>> {
        sources.iter().map(|s| parser::parse_file(s)).collect()
    }

    fn analyze_sources(&self, sources: &[parser::SourceFile]) -> Result<Vec<analyzer::AnalysisResult>> {
        sources.iter().map(|s| analyzer::analyze(s)).collect()
    }

    fn generate_code(
        &self,
        sources: &[parser::SourceFile],
        analyses: &[analyzer::AnalysisResult],
    ) -> Result<Vec<codegen::GeneratedModule>> {
        sources.iter()
            .zip(analyses.iter())
            .map(|(s, a)| codegen::generate(s, a))
            .collect()
    }

    fn write_generated(&self, modules: &[codegen::GeneratedModule]) -> Result<()> {
        let cache_dir = self.cache.generated_dir();

        for module in modules {
            let rel_path = module.name.replace(".r", "");
            let out_path = cache_dir.join(format!("{}.rs", rel_path));
            std::fs::create_dir_all(out_path.parent().unwrap())?;
            std::fs::write(&out_path, &module.source)?;
        }

        Ok(())
    }

    fn build_crate(&self, release: bool) -> Result<()> {
        let manifest = self.cache.generated_cargo_toml();
        let mut cmd = ProcCommand::new("cargo");
        cmd.arg("build");
        if release {
            cmd.arg("--release");
        }
        cmd.arg("--manifest-path").arg(&manifest);

        if !self.options.verbose {
            cmd.stdout(std::process::Stdio::piped());
            cmd.stderr(std::process::Stdio::piped());
        }

        let output = cmd.output()
            .map_err(|e| crate::RuneError::Cargo(e.to_string()))?;

        if !output.status.success() {
            let stderr = String::from_utf8_lossy(&output.stderr);
            return Err(crate::RuneError::Cargo(stderr.to_string()));
        }

        Ok(())
    }

    fn setup_hot_reload(&self) -> Result<()> {
        let hot_dir = self.options.workspace.join("target/hot");
        std::fs::create_dir_all(&hot_dir)?;

        let profile = if matches!(self.options.mode, BuildMode::Dev) {
            "debug"
        } else {
            "release"
        };

        let target_crate = &self.config.build.target_crate;
        let artifact_name = format!("lib{}.so", target_crate);

        let artifact = self.options.workspace
            .join("target")
            .join(profile)
            .join(&artifact_name);

        if artifact.exists() {
            let timestamp = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_millis();

            let hot_name = format!("{}_{}.so", target_crate.replace("-", "_"), timestamp);
            let hot_path = hot_dir.join(&hot_name);

            std::fs::copy(&artifact, &hot_path)?;

            let current = hot_dir.join(".current");
            if current.exists() {
                std::fs::remove_file(&current)?;
            }

            #[cfg(unix)]
            std::os::unix::fs::symlink(&hot_path, &current)?;

            #[cfg(windows)]
            std::os::windows::fs::symlink_file(&hot_path, &current)?;

            if self.options.verbose {
                println!("Hot reload ready: {}", hot_name);
            }
        }

        Ok(())
    }
}

//! # Configuration
//!
//! Rune project configuration (rune.toml).

use std::path::Path;
use serde::{Deserialize, Serialize};

/// Rune project configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RuneConfig {
    /// Project settings
    #[serde(default)]
    pub project: ProjectConfig,

    /// Build settings
    #[serde(default)]
    pub build: BuildConfig,

    /// Development settings
    #[serde(default)]
    pub dev: DevConfig,

    /// Release settings
    #[serde(default)]
    pub release: ReleaseConfig,
}

impl Default for RuneConfig {
    fn default() -> Self {
        Self {
            project: ProjectConfig::default(),
            build: BuildConfig::default(),
            dev: DevConfig::default(),
            release: ReleaseConfig::default(),
        }
    }
}

impl RuneConfig {
    /// Load configuration from a file.
    pub fn load(path: &Path) -> Result<Self, std::io::Error> {
        let content = std::fs::read_to_string(path)?;
        toml::from_str(&content)
            .map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e))
    }

    /// Save configuration to a file.
    pub fn save(&self, path: &Path) -> Result<(), std::io::Error> {
        let content = toml::to_string_pretty(self)
            .map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e))?;
        std::fs::write(path, content)
    }
}

/// Project settings.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ProjectConfig {
    /// Project name
    pub name: String,
    /// Entry point
    pub entry: String,
}

impl Default for ProjectConfig {
    fn default() -> Self {
        Self {
            name: "rune-project".to_string(),
            entry: "src/main.r.ts".to_string(),
        }
    }
}

/// Build settings.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BuildConfig {
    /// Target crate for hot reload
    pub target_crate: String,
    /// Host crate binary
    pub host_crate: String,
}

impl Default for BuildConfig {
    fn default() -> Self {
        Self {
            target_crate: "app".to_string(),
            host_crate: "host".to_string(),
        }
    }
}

/// Development settings.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DevConfig {
    /// Enable hot reload
    pub hot_reload: bool,
    /// Debounce milliseconds
    pub debounce: u64,
}

impl Default for DevConfig {
    fn default() -> Self {
        Self {
            hot_reload: true,
            debounce: 100,
        }
    }
}

/// Release settings.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ReleaseConfig {
