    pub is_host: bool,
}

//! # Cache Manager
//!
//! Manages the rune-cache directory for generated code.

use std::path::PathBuf;

/// Manages the cache directory.
#[derive(Debug)]
pub struct CacheManager {
    /// Base workspace path
    workspace: PathBuf,
}

impl CacheManager {
    /// Create a new cache manager.
    pub fn new(workspace: &std::path::Path) -> std::io::Result<Self> {
        let cache = Self {
            workspace: workspace.to_path_buf(),
        };
        cache.ensure_directories()?;
        Ok(cache)
    }

    /// Get the cache root directory.
    #[must_use]
    pub fn cache_dir(&self) -> PathBuf {
        self.workspace.join("target/rune-cache")
    }

    /// Get the generated code directory.
    #[must_use]
    pub fn generated_dir(&self) -> PathBuf {
        self.cache_dir().join("generated")
    }

    /// Get the generated Cargo.toml path.
    #[must_use]
    pub fn generated_cargo_toml(&self) -> PathBuf {
        self.cache_dir().join("Cargo.toml")
    }

    /// Get the hot reload directory.
    #[must_use]
    pub fn hot_dir(&self) -> PathBuf {
        self.workspace.join("target/hot")
    }

    /// Get the current dylib symlink path.
    #[must_use]
    pub fn current_dylib(&self) -> PathBuf {
        self.hot_dir().join(".current")
    }

    /// Ensure all cache directories exist.
    fn ensure_directories(&self) -> std::io::Result<()> {
        std::fs::create_dir_all(self.cache_dir())?;
        std::fs::create_dir_all(self.generated_dir())?;
        std::fs::create_dir_all(self.hot_dir())?;
        Ok(())
    }

    /// Clean the cache.
    pub fn clean(&self) -> std::io::Result<()> {
        if self.cache_dir().exists() {
            std::fs::remove_dir_all(self.cache_dir())?;
        }
        self.ensure_directories()?;
        Ok(())
    }

    /// Get the path to a specific generated module.
    #[must_use]
    pub fn module_path(&self, module_name: &str) -> PathBuf {
        self.generated_dir().join(format!("{}.rs", module_name))
    }

    /// Check if cache is valid for given sources.
    #[must_use]
    pub fn is_valid(&self, sources: &[PathBuf]) -> bool {
        if !self.generated_cargo_toml().exists() {
            return false;
        }

        for source in sources {
            if !source.exists() {
                continue;
            }

            let source_mtime = match std::fs::metadata(source) {
                Ok(m) => m.modified().ok(),
                Err(_) => None,
            };

            let cache_mtime = match std::fs::metadata(self.generated_cargo_toml()) {
                Ok(m) => m.modified().ok(),
                Err(_) => None,
            };

            if let (Some(src), Some(cache)) = (source_mtime, cache_mtime) {
                if src > cache {
                    return false;
                }
            } else {
                return false;
            }
        }

        true
    }
}

//! # Reload Module
//!
//! Manages hot reload of dylibs and host signaling.

mod watcher;
mod host;

pub use watcher::DylibWatcher;
pub use host::HostSignaler;

/// Error type for reload operations.
#[derive(Debug, thiserror::Error)]
pub enum ReloadError {
    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),

    #[error("Library error: {0}")]
    Library(String),

    #[error("Protocol error: {0}")]
    Protocol(String),
}

/// Result type for reload operations.
pub type ReloadResult<T> = Result<T, ReloadError>;

//! # Dylib Watcher
//!
//! Watches for changes in the hot reload directory and signals the host.

use std::path::{Path, PathBuf};
use std::sync::mpsc;
use std::time::Duration;
use notify::{Watcher, RecommendedWatcher, RecursiveMode, Event, EventKind};
use super::ReloadResult;

/// Watches for dylib changes and notifies the host.
pub struct DylibWatcher {
    /// Watch directory
    watch_dir: PathBuf,
    /// Notify watcher
    watcher: RecommendedWatcher,
    /// Event receiver
    receiver: mpsc::Receiver<ReloadEvent>,
    /// Current dylib path
    current: Option<PathBuf>,
}

impl DylibWatcher {
    /// Create a new watcher.
    pub fn new(hot_dir: &Path) -> ReloadResult<Self> {
        let watch_dir = hot_dir.to_path_buf();
        let (tx, rx) = mpsc::channel();

        let watcher = notify::recommended_watcher(move |res: Result<Event, notify::Error>| {
            if let Ok(event) = res {
                if matches!(event.kind, EventKind::Create(_) | EventKind::Modify(_)) {
                    let _ = tx.send(ReloadEvent::Changed);
                }
            }
        })
        .map_err(|e| super::ReloadError::Library(e.to_string()))?;

        let mut watcher = watcher;
        watcher
            .watch(&watch_dir, RecursiveMode::NonRecursive)
            .map_err(|e| super::ReloadError::Library(e.to_string()))?;

        Ok(Self {
            watch_dir,
            watcher,
            receiver: rx,
            current: None,
        })
    }

    /// Poll for changes with timeout.
    #[must_use]
    pub fn poll(&mut self, timeout: Duration) -> Option<ReloadEvent> {
        match self.receiver.recv_timeout(timeout) {
            Ok(event) => Some(event),
            Err(mpsc::RecvTimeoutError::Timeout) => None,
            Err(mpsc::RecvTimeoutError::Disconnected) => Some(ReloadEvent::Disconnected),
        }
    }

    /// Check if the current dylib has changed.
    pub fn check_current(&mut self) -> ReloadResult<Option<PathBuf>> {
        let current_link = self.watch_dir.join(".current");

        if !current_link.exists() {
            return Ok(None);
        }

        let target = std::fs::read_link(&current_link)?;

        if self.current.as_ref() != Some(&target) {
            self.current = Some(target.clone());
            return Ok(Some(target));
        }

        Ok(None)
    }

    /// Get the current dylib path.
    #[must_use]
    pub fn current_path(&self) -> Option<&Path> {
        self.current.as_deref()
    }

    /// Unwatch and clean up.
    pub fn unwatch(mut self) {
        let _ = self.watcher.unwatch(&self.watch_dir);
    }
}

/// Events from the watcher.
#[derive(Debug, Clone)]
pub enum ReloadEvent {
    /// A new dylib is available
    Changed,
    /// The channel was disconnected
    Disconnected,
}

//! # Host Signaler
//!
//! Signals the host binary to reload the dylib.

use std::path::{Path, PathBuf};
use std::fs;
use std::time::{SystemTime, UNIX_EPOCH};
use super::ReloadResult;

/// Signals the host to reload.
pub struct HostSignaler {
    /// Signal file path
    signal_path: PathBuf,
    /// Hot directory
    hot_dir: PathBuf,
}

impl HostSignaler {
    /// Create a new signaler.
    pub fn new(hot_dir: &Path) -> ReloadResult<Self> {
        let signal_path = hot_dir.join(".reload-signal");
        Ok(Self {
            signal_path,
            hot_dir: hot_dir.to_path_buf(),
        })
    }

    /// Signal the host to reload.
    pub fn signal(&self) -> ReloadResult<()> {
        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_nanos();

        fs::write(&self.signal_path, timestamp.to_string())?;
        Ok(())
    }

    /// Clear the signal.
    pub fn clear(&self) -> ReloadResult<()> {
        if self.signal_path.exists() {
            fs::remove_file(&self.signal_path)?;
        }
        Ok(())
    }

    /// Get the path to the current dylib.
    #[must_use]
    pub fn current_dylib(&self) -> ReloadResult<Option<PathBuf>> {
        let current = self.hot_dir.join(".current");

        if !current.exists() {
            return Ok(None);
        }

        let target = fs::read_link(&current)?;
        Ok(Some(target))
    }

    /// Check if host should restart (protocol changed).
    #[must_use]
    pub fn should_restart(&self) -> ReloadResult<bool> {
        let restart_file = self.hot_dir.join(".restart-needed");
        Ok(restart_file.exists())
    }

    /// Mark that a restart is needed.
    pub fn mark_restart_needed(&self) -> ReloadResult<()> {
        let restart_file = self.hot_dir.join(".restart-needed");
        fs::write(&restart_file, "1")?;
        Ok(())
    }

    /// Clear the restart marker.
    pub fn clear_restart_needed(&self) -> ReloadResult<()> {
        let restart_file = self.hot_dir.join(".restart-needed");
        if restart_file.exists() {
            fs::remove_file(&restart_file)?;
        }
        Ok(())
    }
}

