//! # Source File Handling
//!
//! Manages source file parsing with SWC.

use std::fs;
use std::path::{Path, PathBuf};
use swc_common::{errors::Handler, sync::Lrc, FileName, SourceMap};
use swc_ecma_parser::{lexer::Lexer, Parser, StringInput, Syntax, TsConfig};
use crate::{ParseError, Result};

/// Kind of source file.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SourceKind {
    /// Standard TypeScript file (.r.ts)
    TypeScript,
    /// TSX file (.r.tsx)
    Tsx,
}

/// A parsed Rune source file.
#[derive(Debug, Clone)]
pub struct SourceFile {
    /// File path
    pub path: PathBuf,
    /// Kind of source file
    pub kind: SourceKind,
    /// Raw source text
    pub source: String,
    /// Module name for display
    pub name: String,
    /// Whether parsing was successful
    pub valid: bool,
    /// Parse errors if any
    pub errors: Vec<ParseError>,
}

impl SourceFile {
    /// Parse a source file from a path using SWC.
    pub fn parse(path: &Path, kind: SourceKind) -> Result<Self> {
        if !path.exists() {
            return Err(ParseError::NotFound(path.display().to_string()).into());
        }

        let source = fs::read_to_string(path)?;

        let name = path
            .file_stem()
            .and_then(|s| s.to_str())
            .unwrap_or("module")
            .to_string();

        // Parse with SWC
        let cm: Lrc<SourceMap> = Default::default();
        let fm = cm.new_source_file(
            FileName::Custom(path.display().to_string()).into(),
            source.clone(),
        );

        let syntax = match kind {
            SourceKind::TypeScript => Syntax::Typescript(TsConfig {
                tsx: false,
                ..Default::default()
            }),
            SourceKind::Tsx => Syntax::Tsx(TsConfig {
                tsx: true,
                ..Default::default()
            }),
        };

        let handlers = Handler::with_tty_emitter(
            swc_common::errors::ColorConfig::Never,
            true,
            false,
            Some(cm.clone()),
        );

        let lexer = Lexer::new(syntax, Default::default(), StringInput::from(&*fm), None);
        let mut parser = Parser::new_from(lexer);

        let _module = parser.parse_module();

        let errors: Vec<ParseError> = parser
            .take_errors()
            .into_iter()
            .map(|e| ParseError::Parse(format!("{:?}", e)))
            .collect();

        let valid = errors.is_empty();

        Ok(Self {
            path: path.to_path_buf(),
            kind,
            source,
            name,
            valid,
            errors,
        })
    }

    /// Get line and column from byte offset.
    pub fn location_from_offset(&self, offset: u32) -> (u32, u32) {
        let mut line = 1u32;
        let mut col = 1u32;
        let mut pos = 0u32;

        for c in self.source.chars() {
            if pos >= offset {
                break;
            }
            if c == '\n' {
                line += 1;
                col = 1;
            } else {
                col += 1;
            }
            pos += 1;
        }

        (line, col)
    }

    /// Get the module name.
    pub fn module_name(&self) -> &str {
        &self.name
    }

    /// Check if this is a TSX file.
    pub fn is_tsx(&self) -> bool {
        self.kind == SourceKind::Tsx
    }
}

/// Parse diagnostics module.
pub mod diagnostics {
    use crate::ParseError;

    /// Accumulated parse diagnostics.
    #[derive(Debug, Default)]
    pub struct ParseDiagnostics {
        errors: Vec<ParseError>,
    }

    impl ParseDiagnostics {
        /// Create a new diagnostics collector.
        #[must_use]
        pub fn new() -> Self {
            Self { errors: Vec::new() }
        }

        /// Add an error.
        pub fn add_error(&mut self, err: ParseError) {
            self.errors.push(err);
        }

        /// Check if there are any errors.
        #[must_use]]
        pub fn has_errors(&self) -> bool {
            !self.errors.is_empty()
        }

        /// Get all errors.
        #[must_use]]
        pub fn errors(&self) -> &[ParseError] {
            &self.errors
        }

        /// Take all errors, leaving an empty collector.
        pub fn take_errors(&mut self) -> Vec<ParseError> {
            std::mem::take(&mut self.errors)
        }
    }

    impl std::fmt::Display for ParseDiagnostics {
        fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
            write!(f, "Parse errors: {}", self.errors.len())
        }
    }
}

